@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  :root {
    /* shadcn/RNR semantic aliases → Packed tokens */
    --background: 33 52.9% 96.7%;
    --foreground: 32 13.1% 19.4%;
    --card: 0 0% 100%;
    --card-foreground: 32 13.1% 19.4%;
    --popover: 0 0% 100%;
    --popover-foreground: 32 13.1% 19.4%;
    --primary: 18 100% 58.6%;
    --primary-foreground: 0 0% 100%;
    --secondary: 32 42.9% 93.1%;
    --secondary-foreground: 38 13.3% 11.8%;
    --muted: 32 42.9% 93.1%;
    --muted-foreground: 34 12.7% 38.6%;
    --accent: 207 69.6% 51%;
    --accent-foreground: 0 0% 100%;
    --destructive: 0 63% 46.7%;
    --destructive-foreground: 0 0% 100%;
    --border: 33 27.6% 79.4%;
    --input: 33 27.6% 79.4%;
    --ring: 18 100% 58.6%;
    --radius: 0.75rem;

    /* Packed-named extras */
    --brand: 18 100% 58.6%;
    --brand-hover: 17 85.5% 51.2%;
    --brand-press: 16 85.8% 41.4%;
    --brand-subtle: 20 100% 96.5%;
    --on-brand: 0 0% 100%;
    --accent-subtle: 205 81% 95.9%;
    --accent-hover: 207 72% 42%;
    --surface-sunken: 32 42.9% 93.1%;
    --surface-inverse: 38 13.3% 11.8%;
    --on-inverse: 33 52.9% 96.7%;
    --strong: 38 13.3% 11.8%;
    --muted-text: 34 12.7% 38.6%;
    --subtle: 34 12.9% 51.4%;
    --link: 16 85.8% 41.4%;
    --border-subtle: 33 34.4% 87.5%;
    --border-strong: 33 20.2% 65.1%;
    --border-brand: 20 100% 71.6%;

    /* Status fg/bg pairs */
    --status-ontime-fg: 149 55.7% 25.7%;
    --status-ontime-bg: 146 43.8% 93.7%;
    --status-delay-fg: 40 89.1% 32.4%;
    --status-delay-bg: 39 92% 95.1%;
    --status-cancel-fg: 0 62.5% 37.6%;
    --status-cancel-bg: 0 81% 95.9%;
    --status-info-fg: 207 70.9% 33.7%;
    --status-info-bg: 205 81% 95.9%;

    /* Status dot hues (badge) — match packed.ui scale steps */
    --green-500: 149.7 54.1% 40.2%;
    --amber-500: 40.2 82% 50%;
    --red-500: 0 72.3% 56.1%;
  }

  .dark:root {
    --background: 30 13% 9%;
    --foreground: 38 33.3% 85.9%;
    --card: 38 13.3% 11.8%;
    --card-foreground: 38 33.3% 85.9%;
    --popover: 38 13.3% 11.8%;
    --popover-foreground: 38 33.3% 85.9%;
    --primary: 19 100% 63.9%;
    --primary-foreground: 25 30% 7.8%;
    --secondary: 30 17.6% 6.7%;
    --secondary-foreground: 34 46.7% 94.1%;
    --muted: 30 17.6% 6.7%;
    --muted-foreground: 36 17.4% 63.9%;
    --accent: 205 68.4% 55.3%;
    --accent-foreground: 0 0% 100%;
    --destructive: 0 63% 46.7%;
    --destructive-foreground: 0 0% 100%;
    --border: 33 15.8% 22.4%;
    --input: 33 15.8% 22.4%;
    --ring: 19 100% 63.9%;

    --brand: 19 100% 63.9%;
    --brand-hover: 20 100% 71.6%;
    --brand-press: 18 100% 58.6%;
    --brand-subtle: 23 40% 11.8%;
    --on-brand: 25 30% 7.8%;
    --accent-subtle: 207 50% 14.1%;
    --accent-hover: 207 72% 42%;
    --surface-sunken: 30 17.6% 6.7%;
    --surface-inverse: 33 52.9% 96.7%;
    --on-inverse: 38 13.3% 11.8%;
    --strong: 34 46.7% 94.1%;
    --muted-text: 36 17.4% 63.9%;
    --subtle: 35 11.6% 48.8%;
    --link: 20 100% 71.6%;
    --border-subtle: 32 14.9% 17.1%;
    --border-strong: 33 16.2% 29%;
    --border-brand: 18 100% 58.6%;

    --status-ontime-fg: 146 54% 63.3%;
    --status-ontime-bg: 148 40% 11.8%;
    --status-delay-fg: 40 82.6% 66.3%;
    --status-delay-bg: 41 46.7% 11.8%;
    --status-cancel-fg: 0 77.3% 74.1%;
    --status-cancel-bg: 0 37.3% 13.1%;
    --status-info-fg: 205 77.8% 71.8%;
    --status-info-bg: 207 50% 14.1%;

    --green-500: 149.7 54.1% 40.2%;
    --amber-500: 40.2 82% 50%;
    --red-500: 0 72.3% 56.1%;
  }
}

const { hairlineWidth } = require('nativewind/theme');

/** @type {import('tailwindcss').Config} */
module.exports = {
  darkMode: 'class',
  content: ['./app/**/*.{ts,tsx}', './components/**/*.{ts,tsx}'],
  presets: [require('nativewind/preset')],
  theme: {
    extend: {
      colors: {
        border: 'hsl(var(--border))',
        'border-subtle': 'hsl(var(--border-subtle))',
        'border-strong': 'hsl(var(--border-strong))',
        'border-brand': 'hsl(var(--border-brand))',
        input: 'hsl(var(--input))',
        ring: 'hsl(var(--ring))',
        app: 'hsl(var(--background))',
        background: 'hsl(var(--background))',
        foreground: 'hsl(var(--foreground))',
        strong: 'hsl(var(--strong))',
        'muted-text': 'hsl(var(--muted-text))',
        subtle: 'hsl(var(--subtle))',
        link: 'hsl(var(--link))',
        'surface-sunken': 'hsl(var(--surface-sunken))',
        'surface-inverse': 'hsl(var(--surface-inverse))',
        'on-inverse': 'hsl(var(--on-inverse))',
        primary: {
          DEFAULT: 'hsl(var(--primary))',
          foreground: 'hsl(var(--primary-foreground))',
        },
        brand: {
          DEFAULT: 'hsl(var(--brand))',
          hover: 'hsl(var(--brand-hover))',
          press: 'hsl(var(--brand-press))',
          subtle: 'hsl(var(--brand-subtle))',
        },
        'on-brand': 'hsl(var(--on-brand))',
        secondary: {
          DEFAULT: 'hsl(var(--secondary))',
          foreground: 'hsl(var(--secondary-foreground))',
        },
        destructive: {
          DEFAULT: 'hsl(var(--destructive))',
          foreground: 'hsl(var(--destructive-foreground))',
        },
        muted: {
          DEFAULT: 'hsl(var(--muted))',
          foreground: 'hsl(var(--muted-foreground))',
        },
        accent: {
          DEFAULT: 'hsl(var(--accent))',
          foreground: 'hsl(var(--accent-foreground))',
          subtle: 'hsl(var(--accent-subtle))',
          hover: 'hsl(var(--accent-hover))',
        },
        popover: {
          DEFAULT: 'hsl(var(--popover))',
          foreground: 'hsl(var(--popover-foreground))',
        },
        card: {
          DEFAULT: 'hsl(var(--card))',
          foreground: 'hsl(var(--card-foreground))',
        },
        status: {
          'ontime-fg': 'hsl(var(--status-ontime-fg))',
          'ontime-bg': 'hsl(var(--status-ontime-bg))',
          'delay-fg': 'hsl(var(--status-delay-fg))',
          'delay-bg': 'hsl(var(--status-delay-bg))',
          'cancel-fg': 'hsl(var(--status-cancel-fg))',
          'cancel-bg': 'hsl(var(--status-cancel-bg))',
          'info-fg': 'hsl(var(--status-info-fg))',
          'info-bg': 'hsl(var(--status-info-bg))',
        },
        green: {
          500: 'hsl(var(--green-500))',
        },
        amber: {
          500: 'hsl(var(--amber-500))',
        },
        red: {
          500: 'hsl(var(--red-500))',
        },
      },
      fontFamily: {
        sans: ['Figtree_400Regular'],
        'sans-medium': ['Figtree_500Medium'],
        'sans-semibold': ['Figtree_600SemiBold'],
        'sans-bold': ['Figtree_700Bold'],
        serif: ['Lora_600SemiBold'],
        'serif-bold': ['Lora_700Bold'],
        mono: ['DMMono_400Regular'],
        'mono-medium': ['DMMono_500Medium'],
      },
      borderRadius: {
        xs: '6px',
        sm: '8px',
        md: '12px',
        lg: '16px',
        xl: '20px',
        '2xl': '28px',
        '3xl': '36px',
        pill: '999px',
      },
      borderWidth: {
        hairline: hairlineWidth(),
      },
      boxShadow: {
        xs: '0px 1px 2px rgba(56, 50, 43, 0.06)',
        sm: '0px 1px 3px rgba(56, 50, 43, 0.08)',
        md: '0px 4px 12px rgba(56, 50, 43, 0.08)',
        lg: '0px 12px 28px rgba(56, 50, 43, 0.10)',
        xl: '0px 24px 56px rgba(56, 50, 43, 0.14)',
        card: '0px 1px 3px rgba(56, 50, 43, 0.08)',
        'card-hover': '0px 4px 12px rgba(56, 50, 43, 0.08)',
        brand: '0px 8px 22px rgba(237, 84, 24, 0.28)',
        cta: '0px 8px 22px rgba(237, 84, 24, 0.28)',
      },
      transitionTimingFunction: {
        soft: 'cubic-bezier(0.34, 1.3, 0.64, 1)',
        out: 'cubic-bezier(0.22, 1, 0.36, 1)',
        'in-out': 'cubic-bezier(0.65, 0, 0.35, 1)',
      },
      transitionDuration: {
        fast: '120ms',
        base: '200ms',
        slow: '320ms',
      },
      keyframes: {
        'accordion-down': {
          from: { height: '0' },
          to: { height: 'var(--radix-accordion-content-height)' },
        },
        'accordion-up': {
          from: { height: 'var(--radix-accordion-content-height)' },
          to: { height: '0' },
        },
      },
      animation: {
        'accordion-down': 'accordion-down 0.2s ease-out',
        'accordion-up': 'accordion-up 0.2s ease-out',
      },
    },
  },
  future: {
    hoverOnlyWhenSupported: true,
  },
  plugins: [require('tailwindcss-animate')],
};
